import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

import { Clickable } from '@ggui-ai/design/interact';
import { RadioGroup, Checkbox, TextArea, Input, Button, Progress, Stack, Heading, Text, Box, Card, Container } from '@ggui-ai/design/primitives';

export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: '',
  });

  const [errors, setErrors] = useState({ name: false, email: false });

  const isValidEmail = (email: string) => /\S+@\S+\.\S+/.test(email);

  const validateStep1 = () => {
    const nameErr = !formData.name;
    const emailErr = !isValidEmail(formData.email);
    setErrors({ name: nameErr, email: emailErr });
    return !nameErr && !emailErr;
  };

  const nextStep = () => {
    if (step === 1 && !validateStep1()) return;
    setStep((s) => s + 1);
  };

  const prevStep = () => setStep((s) => s - 1);

  const submit = useAction<ActionSubmitPayload>('submit');

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  const isNextDisabled = useMemo(() => {
    if (step === 1) return !formData.name || !isValidEmail(formData.email);
    if (step === 2) return formData.satisfaction === 0;
    return false;
  }, [step, formData]);

  const renderContent = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Input label="Name" value={formData.name} onChange={(v) => setFormData({ ...formData, name: v })} error={errors.name ? 'Name is required' : ''} />
            <Input label="Email" value={formData.email} onChange={(v) => setFormData({ ...formData, email: v })} error={errors.email ? 'Invalid email format' : ''} />
          </Stack>
        );
      case 2:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>How satisfied are you?</Heading>
            <RadioGroup label="Satisfaction" value={String(formData.satisfaction)} onChange={(v) => setFormData({ ...formData, satisfaction: Number(v) })} options={props.satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))} />
          </Stack>
        );
      case 3:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Feature Interests</Heading>
            {props.featureOptions.map((f) => (
              <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(c) => setFormData({ ...formData, features: c ? [...formData.features, f] : formData.features.filter((i) => i !== f) })} />
            ))}
          </Stack>
        );
      case 4:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Comments & Review</Heading>
            <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData({ ...formData, comments: v })} maxLength={500} showCount />
            <Box padding="var(--ggui-spacing-2)" style={{ border: '1px solid var(--ggui-color-border-default)' }}>
              <Heading level={5}>Summary</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Satisfaction: {formData.satisfaction}</Text>
              <Text>Features: {formData.features.join(', ')}</Text>
            </Box>
          </Stack>
        );
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Text variant="label">Step {Math.min(step, 4)} of 4</Text>
          <Progress value={Math.min(step, 4) * 25} max={100} />
        </Stack>
        <Box>{renderContent()}</Box>
        <Row gap="var(--ggui-spacing-4)" justify="between">
          {step > 1 ? (
            <Button onClick={prevStep}>Back</Button>
          ) : (
            <div />
          )}
          {step < 4 ? (
            <Button disabled={isNextDisabled} onClick={nextStep}>
              Next
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

