import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




const TaskCard = (props: { 
  task: any, 
  onMove: (taskId: string, newColumn: string) => void,
  onEdit: (task: any) => void
}) => {
  const { task, onMove, onEdit } = props;
  const columns = [{ id: 'todo', name: 'To Do' }, { id: 'in-progress', name: 'In Progress' }, { id: 'done', name: 'Done' }];

  return (
    <Card padding="var(--ggui-spacing-3)" shadow="sm" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        <Row justify="between" align="center">
          <Text variant="body" as={Clickable} onDoubleClick={() => onEdit(task)} onClick={() => onEdit(task)}>{task.title}</Text>
          <Badge variant="default" size="sm">{task.priority?.toUpperCase()}</Badge>
        </Row>
        <Row justify="between" align="center">
          <Avatar name={task.assignee || 'U'} size={32} />
          <Text variant="caption">{task.dueDate}</Text>
        </Row>
        <Row gap="var(--ggui-spacing-1)">
          {columns.map(c => (
            <Button key={c.id} size="xs" variant="ghost" as={Clickable} onClick={() => onMove(task.id, c.id)} disabled={task.column === c.id}>
              To {c.name}
            </Button>
          ))}
        </Row>
      </Stack>
    </Card>
  );
};




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [editingTask, setEditingTask] = useState<any>(null);
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTask, setNewTask] = useState({ title: '', priority: 'medium' as any });

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task || !task.id) return;
      if (action === 'delete') setTasks(prev => prev.filter(t => t.id !== task.id));
      else setTasks(prev => {
        const index = prev.findIndex(t => t.id === task.id);
        if (index > -1) {
          const next = [...prev];
          next[index] = { ...next[index], ...task };
          return next;
        }
        return [...prev, task];
      });
    }
  }, [taskChanged.latest]);

  const handleMove = useCallback((taskId: string, column: string) => {
    taskUpdate({ action: 'move', taskId, data: { column } });
    setTasks(prev => prev.map(t => t.id === taskId ? { ...t, column } : t));
  }, [taskUpdate]);

  const handleCreate = useCallback(() => {
    const taskId = Math.random().toString();
    const data = { title: newTask.title, priority: newTask.priority, column: addingTo || 'todo' };
    taskUpdate({ action: 'create', taskId, data: data as any });
    setTasks(prev => [...prev, { id: taskId, ...data }]);
    setAddingTo(null);
    setNewTask({ title: '', priority: 'medium' });
  }, [addingTo, newTask, taskUpdate]);

  const handleEdit = useCallback((task: any) => {
    setEditingTask(task);
  }, []);

  const handleUpdate = useCallback(() => {
    if (!editingTask) return;
    const { id, title, priority, column } = editingTask;
    taskUpdate({ action: 'edit', taskId: id, data: { title, priority, column } as any });
    setTasks(prev => prev.map(t => t.id === id ? editingTask : t));
    setEditingTask(null);
  }, [editingTask, taskUpdate]);



  const summary = useMemo(() => ({
    total: tasks.length,
    completed: tasks.filter(t => t.column === 'done').length
  }), [tasks]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center">
          <Heading level={1}>Task Board</Heading>
          <Row gap="var(--ggui-spacing-4)">
            <Badge variant="primary" size="lg">Total: {summary.total}</Badge>
            <Badge variant="success" size="lg">Done: {summary.completed}</Badge>
          </Row>
        </Row>
        <Row gap="var(--ggui-spacing-4)" align="start">
          {(props.columns || []).map(col => (
            <Stack key={col.id} gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
              <Card padding="var(--ggui-spacing-2)">
                <Heading level={4}>{col.name} ({tasks.filter(t => t.column === col.id).length})</Heading>
              </Card>
              <Stack gap="var(--ggui-spacing-3)">
                {tasks.filter(t => t.column === col.id).map(t => (
                  <TaskCard key={t.id} task={t} onMove={handleMove} onEdit={handleEdit} />
                ))}
              </Stack>
              <Button variant="outline" as={Clickable} onClick={() => setAddingTo(col.id)}>+ Add Task</Button>
            </Stack>
          ))}
        </Row>
        <Modal open={!!editingTask || !!addingTo} onClose={() => { setEditingTask(null); setAddingTo(null); }} title={editingTask ? "Edit Task" : "New Task"}>
          <Stack gap="var(--ggui-spacing-4)">
            <Input label="Title" value={editingTask?.title || newTask.title} onChange={(v: string) => editingTask ? setEditingTask({ ...editingTask, title: v }) : setNewTask({ ...newTask, title: v })} />
            <Select label="Priority" value={editingTask?.priority || newTask.priority} onChange={(v: string) => editingTask ? setEditingTask({ ...editingTask, priority: v }) : setNewTask({ ...newTask, priority: v })} options={[{ value: 'low', label: 'Low' }, { value: 'medium', label: 'Medium' }, { value: 'high', label: 'High' }]} />
            <Button variant="primary" as={Clickable} onClick={editingTask ? handleUpdate : handleCreate}>{editingTask ? "Save Changes" : "Create Task"}</Button>
          </Stack>
        </Modal>

      </Stack>
    </Container>
  );

}

