// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

// Helper for star ratings
const StarRating = (props: { rating: number }) => {
  const stars = [];
  for (let i = 1; i <= 5; i++) {
    stars.push(
      <Icon
        key={i}
        name={i <= props.rating ? 'star' : 'star-outline'}
        size={16}
        color={i <= props.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
      />
    );
  }
  return <Row gap="var(--ggui-spacing-1)">{stars}</Row>;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  const [quantity, setQuantity] = useState(1);

  const product = props.product;
  const isOutOfStock = (product.stock || 0) <= 0;

  const handleAddToCart = useCallback(() => {
    if (product.id) {
      addToCart({ productId: product.id, quantity });
    }
  }, [addToCart, product.id, quantity]);

  const tabs = useMemo(() => [
    {
      key: 'desc',
      label: 'Description',
      content: <Text>{product.description || 'No description available.'}</Text>
    },
    {
      key: 'specs',
      label: 'Specifications',
      content: (
        <Stack gap="var(--ggui-spacing-2)">
          {((product.specifications || []) as any[]).map((spec: any, i: number) => (
            <Row key={i} gap="var(--ggui-spacing-2)">
              <Text weight="semibold" is="span">{spec.key}:</Text>
              <Text is="span">{spec.value}</Text>
            </Row>
          ))}
        </Stack>
      )
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)">
          {((product.reviews || []) as any[]).map((review: any, i: number) => (
            <Card key={i} padding="var(--ggui-spacing-3)" border>
              <Stack gap="var(--ggui-spacing-1)">
                <Text weight="semibold">{review.author}</Text>
                <StarRating rating={review.rating} />
                <Text>{review.text}</Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
              </Stack>
            </Card>
          ))}
        </Stack>
      )
    }
  ], [product.description, product.specifications, product.reviews]);

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row gap="var(--ggui-spacing-8)" align="start">
          <Card padding="var(--ggui-spacing-0)" style={{ width: '400px', height: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--ggui-color-surfaceVariant)' }}>
            <Heading level={2} color="var(--ggui-color-onSurfaceVariant)">{product.name || 'Product Image'}</Heading>
          </Card>

          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
            <Heading level={1}>{product.name}</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Heading level={3}>{product.currency}{product.price?.toFixed(2)}</Heading>
              <StarRating rating={product.rating || 0} />
            </Row>
            <Badge variant={(product.stock || 0) > 5 ? 'success' : 'warning'}>
              {(product.stock || 0) > 0 ? ((product.stock || 0) > 5 ? 'In Stock' : 'Low Stock') : 'Out of Stock'}
            </Badge>

            <Divider />

            <Row gap="var(--ggui-spacing-4)" align="center">
              <Input
                label="Quantity"
                type="number"
                value={quantity.toString()}
                onChange={(val) => setQuantity(Math.max(1, Math.min(product.stock || 1, parseInt(val) || 1)))}
