// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

// Helper to group consecutive messages from same sender
const groupMessages = (msgs: Array<{ sender?: string; text?: string; timestamp?: string }>) => {
  const grouped: Array<{ sender: string; messages: Array<{ text: string; timestamp: string }> }> = [];
  msgs.forEach((m) => {
    if (!m.sender || !m.text || !m.timestamp) return;
    const last = grouped[grouped.length - 1];
    if (last && last.sender === m.sender) {
      last.messages.push({ text: m.text, timestamp: m.timestamp });
    } else {
      grouped.push({ sender: m.sender, messages: [{ text: m.text, timestamp: m.timestamp }] });
    }
  });
  return grouped;
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  const [input, setInput] = useState('');
  const [messages, setMessages] = useState(props.messages || []);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (props.messages) setMessages(props.messages);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = useCallback(() => {
    if (input.trim()) {
      const timestamp = new Date().toISOString();
      const msg = { sender: props.currentUser, text: input, timestamp };
      setMessages((prev) => [...prev, msg]);
      sendMessage({ text: input, timestamp });
      setInput('');
    }
  }, [input, props.currentUser, sendMessage]);
  const groupedMessages = useMemo(() => groupMessages(messages), [messages]);
  const isTyping = typing.latest?.active ? typing.latest : null;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '80vh' }}>
        <Card padding="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3}>{props.title}</Heading>
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
              <Badge variant="default">{props.participantCount} Participants</Badge>
              {isTyping && (
                <Text variant="caption" color="var(--ggui-color-primary-600)">
                  {isTyping.sender} is typing...
                </Text>
              )}
            </Stack>
          </Row>
        </Card>

        <Box style={{ flex: 1, overflowY: 'auto' }} padding="var(--ggui-spacing-2)">
          <Stack gap="var(--ggui-spacing-4)">
            {groupedMessages.map((group, idx) => (
              <Stack key={idx} align={group.sender === props.currentUser ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{group.sender}</Text>
                {group.messages.map((m, mIdx) => (
                  <Box
                    key={mIdx}
                    padding="var(--ggui-spacing-2)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    background={group.sender === props.currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                  >
                    <Text color={group.sender === props.currentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>
                      {m.text}
                    </Text>
                    <Text variant="caption" color={group.sender === props.currentUser ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurfaceVariant)'}>
                      {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </Text>
                  </Box>
                ))}
              </Stack>
            ))}
            <div ref={messagesEndRef} />
          </Stack>
        </Box>

        <Row gap="var(--ggui-spacing-2)">
          <Box style={{ flex: 1 }}>
            <Input
              label="Compose"
              value={input}
              onChange={setInput}
              placeholder="Type your message..."
              onKeyDownCapture={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
            />
          </Box>
          <Button
            as={Clickable}
            onClick={handleSend}
            disabled={!input.trim()}
          >
            Send
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

