                      <Text size="3xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Step 2: Preferences</Heading>
              <Select label="Role" value={formData.role} options={props.roleOptions.map(r => ({ value: r, label: r }))} onChange={(v) => setFormData({ ...formData, role: v })} />
              <Toggle label="Enable Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
              <Stack gap="var(--ggui-spacing-2)">
                <Text variant="label">Theme</Text>
                <RadioGroup value={formData.theme} onChange={(v) => setFormData({ ...formData, theme: v })} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
              </Stack>
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Step 3: Review</Heading>
              <Stack gap="var(--ggui-spacing-2)">
                <Text><b>Name:</b> {formData.name}</Text>
                <Text><b>Email:</b> {formData.email}</Text>
                <Text><b>Avatar:</b> {formData.avatar}</Text>
                <Text><b>Role:</b> {formData.role}</Text>
                <Text><b>Notifications:</b> {formData.emailNotifications ? 'On' : 'Off'}</Text>
                <Text><b>Theme:</b> {formData.theme}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Row justify="between">
          <Button variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>Next</Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
